import type { NotificationChannel, NotificationType } from './notification.js';

export type DeliveryStatus = 'delivered' | 'failed' | 'suppressed';

export interface NotificationLogEntry {
  id: string;
  notificationId: string;
  recipient: string;
  recipientUserId?: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  body: string;
  status: DeliveryStatus;
  error?: string;
  timestamp: Date;
  metadata?: Record<string, unknown>;
}

export interface NotificationHistoryQuery {
  userId?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  from?: Date;
  to?: Date;
}

import type {
  NotificationLogEntry,
  NotificationHistoryQuery,
} from '../models/notification-log.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');
  private entries: NotificationLogEntry[] = [];

  log(entry: Omit<NotificationLogEntry, 'id'>): NotificationLogEntry {
    const logEntry: NotificationLogEntry = {
      ...entry,
      id: generateLogId(),
    };
    this.entries.push(logEntry);
    this.logger.info(
      `Logged notification ${logEntry.notificationId} [${logEntry.status}] via ${logEntry.channel} to ${logEntry.recipient}`,
    );
    return logEntry;
  }

  query(filter: NotificationHistoryQuery): NotificationLogEntry[] {
    return this.entries.filter((entry) => {
      if (filter.userId !== undefined && entry.recipientUserId !== filter.userId) {
        return false;
      }
      if (filter.type !== undefined && entry.type !== filter.type) {
        return false;
      }
      if (filter.channel !== undefined && entry.channel !== filter.channel) {
        return false;
      }
      if (filter.status !== undefined && entry.status !== filter.status) {
        return false;
      }
      if (filter.from !== undefined && entry.timestamp < filter.from) {
        return false;
      }
      if (filter.to !== undefined && entry.timestamp > filter.to) {
        return false;
      }
      return true;
    });
  }

  getByUser(userId: string): NotificationLogEntry[] {
    return this.query({ userId });
  }

  getByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
    return this.query({ type });
  }

  getByChannel(channel: NotificationLogEntry['channel']): NotificationLogEntry[] {
    return this.query({ channel });
  }

  getByDateRange(from: Date, to: Date): NotificationLogEntry[] {
    return this.query({ from, to });
  }

  getAll(): NotificationLogEntry[] {
    return [...this.entries];
  }

  count(): number {
    return this.entries.length;
  }

  clear(): void {
    this.entries = [];
  }
}

