import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
import type { NotificationAdapter } from '../../src/adapters/notification.adapter.js';

function makeUser(overrides: Partial<OrderCreatedEvent['user']> = {}): OrderCreatedEvent['user'] {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<OrderCreatedEvent['order']> = {}): OrderCreatedEvent['order'] {
  return {
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    resetNotificationIdCounter();
    resetLogIdCounter();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    historyService = new NotificationHistoryService();
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    notificationService.setHistoryService(historyService);
  });

  describe('logging', () => {
    it('should log a delivered notification', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(historyService.count()).toBe(1);
      const entries = historyService.getAll();
      expect(entries[0]?.status).toBe('delivered');
      expect(entries[0]?.channel).toBe('email');
      expect(entries[0]?.type).toBe('order-confirmation');
      expect(entries[0]?.recipient).toBe('alice@example.com');
      expect(entries[0]?.recipientUserId).toBe('user-1');
      expect(entries[0]?.subject).toContain('Order Confirmation');
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser({ id: 'user-2', email: 'bob@example.com', name: 'Bob' }),
        timestamp: new Date(),
      });

      const entries = historyService.getAll();
      expect(entries[0]?.id).toBe('log-0001');
      expect(entries[1]?.id).toBe('log-0002');
    });

    it('should log failed notifications when no adapter registered', async () => {
      const noAdapterService = new NotificationService(new EventBus());
      const freshHistory = new NotificationHistoryService();
      noAdapterService.setHistoryService(freshHistory);

      const freshBus = new EventBus();
      const svc = new NotificationService(freshBus);
      svc.setHistoryService(freshHistory);
      // No adapter registered

      await freshBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(freshHistory.count()).toBe(1);
      const entries = freshHistory.getAll();
      expect(entries[0]?.status).toBe('failed');
      expect(entries[0]?.error).toContain('No adapter registered');
    });

    it('should log suppressed notifications', async () => {
      const preferencesService = new PreferencesService();
      preferencesService.updatePreferences('user-1', {
        email: { enabled: false },
      });
      notificationService.setPreferencesService(preferencesService);

      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(historyService.count()).toBe(1);
      const entries = historyService.getAll();
      expect(entries[0]?.status).toBe('suppressed');
    });

    it('should not log when no history service is set', async () => {
      const plainService = new NotificationService(new EventBus());
      const bus = new EventBus();
      const svc = new NotificationService(bus);
      svc.registerAdapter(new EmailAdapter());
      // No history service set

      await bus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      // No errors thrown — just silently skips logging
      expect(plainService.getNotificationCount()).toBe(0);
    });
  });

  describe('query by user', () => {
    it('should return entries for a specific user', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser({ id: 'user-2', email: 'bob@example.com', name: 'Bob' }),
        timestamp: new Date(),
      });

      expect(historyService.getByUser('user-1')).toHaveLength(1);
      expect(historyService.getByUser('user-2')).toHaveLength(1);
      expect(historyService.getByUser('user-99')).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    it('should return entries for a specific notification type', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(historyService.getByType('order-confirmation')).toHaveLength(1);
      expect(historyService.getByType('welcome')).toHaveLength(1);
      expect(historyService.getByType('order-status-update')).toHaveLength(0);
    });
  });

  describe('query by channel', () => {
    it('should return entries for a specific channel', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(historyService.getByChannel('email')).toHaveLength(1);
      expect(historyService.getByChannel('webhook')).toHaveLength(0);
    });
  });

  describe('query by date range', () => {
    it('should filter entries within a date range', async () => {
      const past = new Date('2025-01-01');
      const future = new Date('2027-01-01');

      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(historyService.getByDateRange(past, future)).toHaveLength(1);
      expect(historyService.getByDateRange(future, new Date('2028-01-01'))).toHaveLength(0);
    });
  });

  describe('compound queries', () => {
    it('should support filtering by multiple criteria', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      const results = historyService.query({
        userId: 'user-1',
        type: 'order-confirmation',
        channel: 'email',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order-confirmation');
    });

    it('should return empty for non-matching compound query', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      const results = historyService.query({
        userId: 'user-1',
        type: 'welcome', // user-1 got order-confirmation, not welcome
      });
      expect(results).toHaveLength(0);
    });

    it('should support filtering by status', async () => {
      const preferencesService = new PreferencesService();
      preferencesService.updatePreferences('user-1', {
        email: { enabled: false },
      });
      notificationService.setPreferencesService(preferencesService);

      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });
      // user-2 has no prefs set → default (all enabled)
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser({ id: 'user-2', email: 'bob@example.com', name: 'Bob' }),
        timestamp: new Date(),
      });

      expect(historyService.query({ status: 'suppressed' })).toHaveLength(1);
      expect(historyService.query({ status: 'delivered' })).toHaveLength(1);
    });
  });

  describe('management', () => {
    it('should clear all entries', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(historyService.count()).toBe(1);
      historyService.clear();
      expect(historyService.count()).toBe(0);
      expect(historyService.getAll()).toHaveLength(0);
    });

    it('should track multiple notifications for the same user', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });
      await eventBus.emit<OrderStatusChangedEvent>({
        type: 'order:status-changed',
        order: makeOrder({ status: 'confirmed' }),
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(historyService.getByUser('user-1')).toHaveLength(2);
    });

    it('should capture notification body and subject in log', async () => {
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser({ name: 'Charlie' }),
        timestamp: new Date(),
      });

      const entries = historyService.getAll();
      expect(entries[0]?.subject).toBe('Welcome to TaskFlow Pro');
      expect(entries[0]?.body).toContain('Charlie');
    });
  });
});

